53		output control_strobe,
54		output control_rd,
55		output control_write,
56		output control_rd_valid,
57		output control_prefill,
58		// length of control_pipe_rd is read_pipe_len+1, see above
59		output [read_pipe_len:0] control_pipe_rd,
60		output [31:0] data_out,
61		input [31:0] data_in
62	);
