70	reg [8:0] repeat_count=0;
71	reg [23:0] isr=0;  // input shift register
72	wire [31:0] next_isr = {isr, idata};
73	reg [63:0] big_r=0;  // command, address, data
74	reg [1:0] c4=0;
75	reg data_phase=0;
76	reg pre_body=0, body=0;
77	reg do_op=0;
78	wire next_do_op = body & &c4 & data_phase;
79	wire set_repeat = ~data_phase & next_isr[29] & enable_bursts;
80	wire set_repeat_view = body & &c4 & set_repeat; // Debug signal
81	reg inc_address=0;
